// === LE DICTIONNAIRE D'AFFLUENCE ===
const traductionsAffluence = {
    "EMPTY": "🟢 Bus vide",
    "MANY_SEATS_AVAILABLE": "🟢 Beaucoup de places",
    "FEW_SEATS_AVAILABLE": "🟡 Peu de places assises",
    "STANDING_ROOM_ONLY": "🟠 Places debout uniquement",
    "CRUSHED_STANDING_ROOM_ONLY": "🔴 Bus bondé",
    "FULL": "🔴 Complet",
    "NOT_ACCEPTING_PASSENGERS": "⚫ Ne prend plus de passagers"
};

let lignesConnues = new Set();
const selectFiltre = document.getElementById('filtre-ligne');
let ligneSelectionnee = 'Toutes';

for (const [codeTcar, vraiNom] of Object.entries(nomsLignes)) {
    lignesConnues.add(codeTcar);
    const option = document.createElement('option');
    option.value = codeTcar;
    option.textContent = 'Ligne ' + vraiNom;
    selectFiltre.appendChild(option);
}

selectFiltre.addEventListener('change', (e) => {
    ligneSelectionnee = e.target.value;
    dessinerTraceLigne(ligneSelectionnee);
    chargerPositionsBus();
});

function dessinerTraceLigne(routeId) {
    if (ligneTracee) {
        map.removeLayer(ligneTracee);
    }

    if (routeId === 'Toutes') return;

    const coordonnees = tracesLignes[routeId];

    if (coordonnees && coordonnees.length > 0) {
        const couleur = infosLignes[routeId] ? infosLignes[routeId].couleur : '#3b82f6';

        ligneTracee = L.polyline(coordonnees, {
            color: couleur,
            weight: 5,
            opacity: 0.7
        }).addTo(map);

        map.fitBounds(ligneTracee.getBounds());
    }
}

function chargerPositionsBus() {
    const tempsActuel = new Date().getTime();
    const urlPositions = 'https://corsproxy.io/?' + encodeURIComponent('https://gtfs.bus-tracker.fr/gtfs-rt/tcar/vehicle-positions.json?nocache=' + tempsActuel);
    const urlTemps = 'https://corsproxy.io/?' + encodeURIComponent('https://gtfs.bus-tracker.fr/gtfs-rt/tcar/trip-updates.json?nocache=' + tempsActuel);

    Promise.all([
        fetch(urlPositions).then(res => res.json()),
        fetch(urlTemps).then(res => res.json())
    ])
        .then(([dataPositions, dataTemps]) => {
            busMarkers.clearLayers();

            const tripUpdates = new Map();
            if (dataTemps && dataTemps.entity) {
                dataTemps.entity.forEach(e => {
                    if (e.tripUpdate && e.tripUpdate.trip && e.tripUpdate.trip.tripId) {
                        tripUpdates.set(e.tripUpdate.trip.tripId, e.tripUpdate);
                    }
                });
            }

            if (dataPositions && dataPositions.entity) {
                dataPositions.entity.forEach(entite => {
                    if (entite.vehicle && entite.vehicle.position) {
                        const lat = entite.vehicle.position.latitude;
                        const lon = entite.vehicle.position.longitude;
                        const rawRouteId = entite.vehicle.trip ? entite.vehicle.trip.routeId : "Inconnue";
                        const tripId = entite.vehicle.trip ? entite.vehicle.trip.tripId : null;
                        const idBus = entite.vehicle.vehicle ? entite.vehicle.vehicle.id : "Inconnu";

                        const destination = (entite.vehicle.vehicle && entite.vehicle.vehicle.label)
                            ? entite.vehicle.vehicle.label
                            : "Destination inconnue";

                        let texteAffluence = "";
                        if (entite.vehicle.occupancyStatus) {
                            const traduction = traductionsAffluence[entite.vehicle.occupancyStatus] || "Inconnue";
                            texteAffluence = `<br>Affluence : <b>${traduction}</b>`;
                        }

                        let nomAffiche = nomsLignes[rawRouteId];
                        if (!nomAffiche) {
                            nomAffiche = rawRouteId.replace("TCAR:", "").replace("TNI:", "").replace("TAE:", "");
                        }

                        if (rawRouteId !== "Inconnue" && !lignesConnues.has(rawRouteId)) {
                            lignesConnues.add(rawRouteId);
                            const option = document.createElement('option');
                            option.value = rawRouteId;
                            option.textContent = 'Ligne ' + nomAffiche;
                            selectFiltre.appendChild(option);
                        }

                        if (ligneSelectionnee !== 'Toutes' && ligneSelectionnee !== rawRouteId) return;

                        let infoTemps = "<i>Pas d'info temps réel</i>";
                        if (tripId && tripUpdates.has(tripId)) {
                            const update = tripUpdates.get(tripId);
                            if (update.stopTimeUpdate && update.stopTimeUpdate.length > 0) {
                                const prochainArret = update.stopTimeUpdate[0];
                                let retardSecondes = prochainArret.departure && prochainArret.departure.delay ? prochainArret.departure.delay : 0;
                                let retardMinutes = Math.round(retardSecondes / 60);

                                if (retardMinutes > 0) infoTemps = `<span style="color:red">En retard de ${retardMinutes} min</span>`;
                                else if (retardMinutes < 0) infoTemps = `<span style="color:green">En avance de ${Math.abs(retardMinutes)} min</span>`;
                                else infoTemps = `<span style="color:green">À l'heure exacte</span>`;
                            }
                        }

                        const marqueur = L.marker([lat, lon], { icon: busIcon });

                        marqueur.bindPopup(`
                            <b>Véhicule n°${idBus}</b><br>
                            Ligne : <b>${nomAffiche}</b><br>
                            Direction : <b>${destination}</b><br>
                            État : ${infoTemps}
                            ${texteAffluence}
                        `);

                        busMarkers.addLayer(marqueur);
                    }
                });
            }

            document.getElementById('heure-maj').textContent = "Dernière mise à jour : " + new Date().toLocaleTimeString();
        })
        .catch(erreur => console.error("Erreur :", erreur));
}

chargerPositionsBus();
setInterval(chargerPositionsBus, 20000);